#include <bits/stdc++.h>
using namespace std;
int n,q,st[100005][30][2],a[100005];
int fun(int l,int r)
{
	int len=r-l+1;
	int maxx=max(st[l][a[len]][1],st[r-(1<<a[len])+1][a[len]][1]);
	int minn=min(st[l][a[len]][0],st[r-(1<<a[len])+1][a[len]][0]);
	return maxx-minn; 
}
int main()
{
	cin>>n>>q;
	a[0]=-1;
	for(int i=1;i<=n;i++)
	{
		cin>>st[i][0][0];
		st[i][0][1]=st[i][0][0];
		a[i]=a[i/2]+1;
	}
	for(int i=1;i<=a[n];i++)
	{
		for(int j=1;j<=n-i+1;j++)
		{
			st[j][i][0]=min(st[j][i-1][0],st[j+(1<<(i-1))][i-1][0]);
			st[j][i][1]=max(st[j][i-1][1],st[j+(1<<(i-1))][i-1][1]);
		}
	}
	for(int i=1;i<=q;i++)
	{
		int l,r;
		cin>>l>>r;
		cout<<fun(l,r)<<'\n';
	}
	return 0;
}
